import React, { useEffect, useState } from 'react';

const CLIENT_ID = 'your_client_id';
const REDIRECT_URI = 'http://localhost:3000/callback';
const AUTH_URL = 'https://your-auth-provider.com/oauth/authorize';
const SCOPES = 'your_scopes';

const App = () => {
  const [accessToken, setAccessToken] = useState(null);

  const handleLogin = () => {
    const url = `${AUTH_URL}?response_type=token&client_id=${CLIENT_ID}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}&scope=${encodeURIComponent(SCOPES)}`;
    window.location.href = url;
  };

  useEffect(() => {
    const hash = window.location.hash;
    if (hash) {
      const token = new URLSearchParams(hash.replace('#', '?')).get('access_token');
      if (token) {
        setAccessToken(token);
        window.location.hash = ''; // Clear the hash to prevent re-parsing
      }
    }
  }, []);

  return (
    <div>
      <h1>OAuth 2.0 Implicit Flow Example</h1>
      {accessToken ? (
        <div>
          <h2>Access Token:</h2>
          <p>{accessToken}</p>
        </div>
      ) : (
        <button onClick={handleLogin}>Login with OAuth</button>
      )}
    </div>
  );
};

export default App;